import posthog from 'posthog-js'

const posthogKey = import.meta.env.VITE_POSTHOG_KEY as string | undefined
const posthogHost = import.meta.env.VITE_POSTHOG_HOST as string | undefined

export const posthogEnabled = Boolean(posthogKey)

if (!posthogEnabled) {
  console.info('Missing VITE_POSTHOG_KEY — PostHog analytics is disabled.')
} else {
  posthog.init(posthogKey!, {
    api_host: posthogHost || 'https://us.i.posthog.com',
    capture_pageview: false,
    capture_pageleave: true,
    autocapture: false,
    respect_dnt: true,
    persistence: 'localStorage',
    loaded: (ph) => {
      if (import.meta.env.DEV) ph.debug()
    },
  })
}

if (posthogEnabled) {
  window.onerror = (_message, _source, _lineno, _colno, error) => {
    if (error) {
      posthog.capture('$exception', {
        $exception_message: error.message,
        $exception_type: error.name,
        $exception_stack_trace_raw: error.stack,
        $exception_source: 'window_onerror',
      })
    }
  }

  window.onunhandledrejection = (event: PromiseRejectionEvent) => {
    const error = event.reason instanceof Error ? event.reason : new Error(String(event.reason))
    posthog.capture('$exception', {
      $exception_message: error.message,
      $exception_type: error.name,
      $exception_stack_trace_raw: error.stack,
      $exception_source: 'unhandled_rejection',
    })
  }
}

export { posthog }

import { useEffect, useRef } from 'react'
import { useLocation } from 'react-router-dom'
import { posthog, posthogEnabled } from '@/lib/posthog'
import { useAuthStore } from '@/stores/authStore'

/** Captures a $pageview event on every pathname change. No-op when PostHog is disabled. */
export function usePostHogPageview() {
  const { pathname } = useLocation()

  useEffect(() => {
    if (!posthogEnabled) return
    posthog.capture('$pageview', { $current_url: window.location.href })
  }, [pathname])
}

/** Identifies/resets the PostHog user when auth state changes. No-op when PostHog is disabled. */
export function usePostHogIdentify() {
  const user = useAuthStore((s) => s.user)
  const identifiedRef = useRef<string | null>(null)

  useEffect(() => {
    if (!posthogEnabled) return

    if (user && identifiedRef.current !== user.id) {
      posthog.identify(user.id, { email: user.email })
      identifiedRef.current = user.id
    } else if (!user && identifiedRef.current) {
      posthog.reset()
      identifiedRef.current = null
    }
  }, [user])
}

import { useEffect } from 'react'
import { Routes, Route } from 'react-router-dom'
import { Header } from '@/components/layout/Header'
