    mockPrefsState.loaded = true
    setupMocks(undefined, {
      data: {
        search: {
          results: [
            { unitID: '1', name: 'NYU', city: 'New York', state: 'NY', distance: 5, myPrice: 20000 },
          ],
          total: 1,
          limit: 20,
          offset: 0,
        },
      },
    })
    renderSearch('/search')
    const searchCall = mockUseQuery.mock.calls.find(
      (call: Array<{ query: unknown; variables?: Record<string, unknown> }>) =>
        getOperationName(call[0].query) === 'Search',
    )
    expect(searchCall).toBeDefined()
    expect(searchCall![0].variables).toEqual(
      expect.objectContaining({
        userLocation: { latitude: 40.7128, longitude: -74.006, state: 'NY' },
      }),
    )
  })

  it('URL location params override saved home location', () => {
    mockPrefsState.homeLatitude = 40.7128
    mockPrefsState.homeLongitude = -74.006
    mockPrefsState.homeState = 'NY'
    mockPrefsState.loaded = true
    renderSearch('/search?userLat=42.0&userLng=-72.0&userState=MA')
    const searchCall = mockUseQuery.mock.calls.find(
      (call: Array<{ query: unknown; variables?: Record<string, unknown> }>) =>
        getOperationName(call[0].query) === 'Search',
    )
    expect(searchCall).toBeDefined()
    expect(searchCall![0].variables).toEqual(
      expect.objectContaining({
        userLocation: { latitude: 42, longitude: -72, state: 'MA' },
      }),
    )
  })

  it('does not auto-apply when preferences are not yet loaded', () => {
    mockPrefsState.homeLatitude = 40.7128
    mockPrefsState.homeLongitude = -74.006
    mockPrefsState.homeState = 'NY'
    mockPrefsState.loaded = false
    renderSearch('/search')
    const searchCall = mockUseQuery.mock.calls.find(
      (call: Array<{ query: unknown; variables?: Record<string, unknown> }>) =>
        getOperationName(call[0].query) === 'Search',
    )
    expect(searchCall).toBeDefined()
    expect(searchCall![0].variables).toEqual(
      expect.objectContaining({ userLocation: null }),
    )
  })

  it('does not auto-apply when saved preferences have no location', () => {
    mockPrefsState.homeLatitude = null
    mockPrefsState.homeLongitude = null
    mockPrefsState.homeState = null
    mockPrefsState.loaded = true
    renderSearch('/search')
    const searchCall = mockUseQuery.mock.calls.find(
      (call: Array<{ query: unknown; variables?: Record<string, unknown> }>) =>
        getOperationName(call[0].query) === 'Search',
    )
    expect(searchCall).toBeDefined()
    expect(searchCall![0].variables).toEqual(
      expect.objectContaining({ userLocation: null }),
    )
  })
})

